				\begin{document}$$\text{Standardized ES}=\frac{{\mathrm{Change}}_{\text{High Load}}- {\mathrm{Change}}_{\text{Low Load}}}{\sqrt{ \frac{{(N}_{1}-1){v}_{1}+ {(N}_{2}-1){v}_{2} }{{N}_{1} + {N}_{2} - 2}}},$$\end{document}Standardized ES=ChangeHigh Load-ChangeLow Load(N1-1)v1+(N2-1)v2N1+N2-2,\documentclass[12pt]{minimal}
