				\begin{document}$$\text{ SE}=\sqrt{\frac{{N}_{1} + {N}_{2} }{{N}_{1} * {N}_{2}}+ \frac{{\mathrm{ES}}^{2} }{{2(N}_{1}+ {N}_{2})}}.$$\end{document}SE=N1+N2N1∗N2+ES22(N1+N2).
